import{_ as a,o as t,c as i,ag as s}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"Team Management","description":"","frontmatter":{},"headers":[],"relativePath":"settings/team.md","filePath":"settings/team.md"}'),n={name:"settings/team.md"};function o(r,e,l,c,m,h){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="team-management" tabindex="-1">Team Management <a class="header-anchor" href="#team-management" aria-label="Permalink to &quot;Team Management&quot;">​</a></h1><p>Invite team members, assign roles, and control who can access what in your workspace.</p><h2 id="inviting-team-members" tabindex="-1">Inviting team members <a class="header-anchor" href="#inviting-team-members" aria-label="Permalink to &quot;Inviting team members&quot;">​</a></h2><ol><li>Go to <strong>Settings &gt; Team</strong> or <strong>Company &gt; Team Members</strong></li><li>Click <strong>Invite Member</strong></li><li>Enter the person&#39;s <strong>email address</strong></li><li>Choose a <strong>role</strong> (see below)</li><li>Click <strong>Send Invitation</strong></li></ol><p>The invitee receives an email with a link to join your workspace. If they don&#39;t have a MyCompanyDesk account, they can create one during the process.</p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>Description</th></tr></thead><tbody><tr><td><strong>Admin</strong></td><td>Full access to everything, including team and billing management</td></tr><tr><td><strong>Member</strong></td><td>Access to assigned features, cannot manage team or billing</td></tr><tr><td><strong>Accountant</strong></td><td>Read-only access with specific accounting views</td></tr></tbody></table><h3 id="admin" tabindex="-1">Admin <a class="header-anchor" href="#admin" aria-label="Permalink to &quot;Admin&quot;">​</a></h3><p>Admins can:</p><ul><li>Manage team members (invite, remove, change roles)</li><li>Access billing and subscription settings</li><li>Configure company settings</li><li>Access all features</li></ul><h3 id="member" tabindex="-1">Member <a class="header-anchor" href="#member" aria-label="Permalink to &quot;Member&quot;">​</a></h3><p>Members have access to the features you assign them. Configure their permissions per feature.</p><h3 id="accountant" tabindex="-1">Accountant <a class="header-anchor" href="#accountant" aria-label="Permalink to &quot;Accountant&quot;">​</a></h3><p>A special role for external accountants:</p><ul><li>View financial data (invoices, expenses, reports)</li><li>Cannot create or modify records (by default)</li><li>Specific permission set for audit purposes</li></ul><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p>Fine-grained permissions let you control access per feature:</p><h3 id="page-access" tabindex="-1">Page access <a class="header-anchor" href="#page-access" aria-label="Permalink to &quot;Page access&quot;">​</a></h3><p>Choose which sections each member can see:</p><ul><li>Invoices</li><li>Quotes</li><li>Expenses</li><li>Customers</li><li>Projects</li><li>Contracts</li><li>Objects</li><li>Time Registration</li><li>Reports</li><li>VAT</li><li>Settings</li></ul><h3 id="edit-permissions" tabindex="-1">Edit permissions <a class="header-anchor" href="#edit-permissions" aria-label="Permalink to &quot;Edit permissions&quot;">​</a></h3><p>For each accessible page, choose whether the member can:</p><ul><li><strong>View only</strong> — Read access, no modifications</li><li><strong>Edit</strong> — Full read/write access</li></ul><h2 id="accountant-contacts" tabindex="-1">Accountant contacts <a class="header-anchor" href="#accountant-contacts" aria-label="Permalink to &quot;Accountant contacts&quot;">​</a></h2><p>Manage external accountant relationships:</p><ol><li>Go to <strong>Settings &gt; Team &gt; Accountants</strong></li><li>Click <strong>Add Accountant</strong></li><li>Enter their name and email</li><li>Click <strong>Invite</strong> to send access</li><li>Configure their specific permissions</li></ol><h3 id="managing-accountant-access" tabindex="-1">Managing accountant access <a class="header-anchor" href="#managing-accountant-access" aria-label="Permalink to &quot;Managing accountant access&quot;">​</a></h3><ul><li><strong>Invite</strong> — Send or resend the access invitation</li><li><strong>Revoke</strong> — Remove access (can be restored later)</li><li><strong>Restore</strong> — Re-enable previously revoked access</li><li><strong>Update permissions</strong> — Change what they can see</li></ul><h2 id="switching-workspaces" tabindex="-1">Switching workspaces <a class="header-anchor" href="#switching-workspaces" aria-label="Permalink to &quot;Switching workspaces&quot;">​</a></h2><p>If you&#39;re a member of multiple workspaces (companies), switch between them:</p><ol><li>Click your account menu</li><li>Select <strong>Switch Workspace</strong></li><li>Choose the workspace</li></ol><p>Or create a <strong>new workspace</strong> from the same menu.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Use the accountant role for your bookkeeper — it provides exactly the access they need</li><li>Set member permissions thoughtfully — not everyone needs access to billing or team settings</li><li>Review team access periodically, especially when team members change roles</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Team management beyond 1 member requires the <strong>Pro</strong> plan. Unlimited members are available on the <strong>Business</strong> plan.</p></div>',35)])])}const u=a(n,[["render",o]]);export{g as __pageData,u as default};
